        capitulo: `
                <div style="text-align: center; margin-top: 30px;">
                    <div style="margin-bottom: 15px;">CAPÍTULO TERCERO</div>
                    <div>RECONOCIMIENTO DE EXISTENCIA</div>
                </div>`,
